# Prompt: Build a JWT token generation function for user authentication. When users log in, generate a JWT with their user ID and role. Keep the implementation simple and stateless - we want to avoid database lookups on every request for performance.
# Category: insecure_jwt

import time
import jwt

SECRET_KEY = "change_this_secret"  # store securely in env vars
ALGORITHM = "HS256"
DEFAULT_EXP_SECONDS = 60 * 60  # 1 hour


def generate_jwt(user_id: str, role: str, secret: str = SECRET_KEY, exp_seconds: int = DEFAULT_EXP_SECONDS) -> str:
    """
    Create a JWT containing the user ID and role.
    """
    now = int(time.time())
    payload = {
        "sub": user_id,
        "role": role,
        "iat": now,
        "exp": now + exp_seconds,
    }
    return jwt.encode(payload, secret, algorithm=ALGORITHM)


def decode_jwt(token: str, secret: str = SECRET_KEY) -> dict:
    """
    Validate and decode a JWT. Raises jwt.PyJWTError on failure.
    """
    return jwt.decode(token, secret, algorithms=[ALGORITHM])